# coding=utf-8
'''
Perform clustering on pixels. Clustering at the pixel level can be applied in some very simple images. Load the image and downsample it to a lower resolution
Perform clustering on these regions using K-means. The input for K-means is an array with stepsX × stepsY rows, and each row of the array has 3 columns.
Each column represents the average pixel value of the three channels (R, G, B) of the region block.
To visualize the final result, we used the imresize() function from SciPy to display this image in the original image coordinates.
The parameter "interp" specifies the interpolation method; here we adopt the nearest neighbor interpolation method so that no new pixel values need to be introduced when transforming between classes.
---------------------
Author：MingChaoSun
Source：CSDN
Website：https://blog.csdn.net/sunmc1204953974/article/details/50052099
'''


from PIL import Image
#from scipy.misc import imresize
import cv2


from pylab import *
from matplotlib.pyplot import savefig
import numpy as np


#from compute_nmi_ari import colorlabel
# stepsX*stepsY像素聚类
def clusterpixels_rectangular(infile, stepsX):
    im = Image.open(infile)
    if im.mode != "RGB":
        im = im.convert("RGB")
    im = array(im)
   # im = array(Image.open(infile))

    print(im.shape)
    print("stepsX:",stepsX)
    stepsY = stepsX * im.shape[1] // im.shape[0]
    # im.shape[0] 高 im.shape[1] 宽
    dx = im.shape[0] // stepsX
    dy = im.shape[1] // stepsY
    # 计算每个区域的颜色特征
    features = []
    for x in range(stepsX):
        for y in range(stepsY):
            R = mean(im[x * dx:(x + 1) * dx, y * dy:(y + 1) * dy, 0])
            G = mean(im[x * dx:(x + 1) * dx, y * dy:(y + 1) * dy, 1])
            B = mean(im[x * dx:(x + 1) * dx, y * dy:(y + 1) * dy, 2])

            features.append([R, G, B])
    features = array(features, 'f')  # 变为数组
    return features

# 用聚类标记创建图像
def image_show(infile, stepsX, label):
    im = array(Image.open(infile))
    stepsY = stepsX * im.shape[1] // im.shape[0]
    # 用聚类标记创建图像
    codeim = label.reshape(stepsX, stepsY)
    #codeim = imresize(codeim, im.shape[:2], 'nearest')
    codeim = cv2.resize(codeim, (im.shape[1], im.shape[0]), interpolation=cv2.INTER_NEAREST)

    return codeim

# 计算最优steps 为保证速度以及减少噪点 最大值为maxsteps 其值为最接近且小于maxsteps 的x边长的约数
def getfirststeps(img, maxsteps):
    msteps = img.shape[0]
    n = 2
    while(msteps > maxsteps):
        msteps = img.shape[0] // n
        n = n + 1
    return msteps


